** Object:  StoredProcedure [dbo].[PARALLEL_mstp_PaymentsPending]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROCEDURE [dbo].[PARALLEL_mstp_PaymentsPending] -- WITH RECOMPILE,ENCRYPTION
  @Client   varchar(50),            --MPC:25/01/2010
  @Module   varchar(50),            --MPC:25/01/2010
  @Mode   varchar(4)    --'FULL' or 'MOVE'  --MPC:25/01/2010

AS

/******************************************************************************

-----------    Mike Cawood SR9 CHANGES April 2008  ----------------------------
--
-- Object  : procedure
-- Name    : PARALLEL_mstp_PaymentsPending.sql
-- Owner   : CTT
-- Created : 26/10/2005
--
-- Call as 
--  PARALLEL_mstp_PaymentsPending 'Openwork', 'Open Access','MOVE'
-- OR
--  PARALLEL_mstp_PaymentsPending 'Openwork', 'Open Access','FULL'
--
Processing changes to bring FIRM definition in line with:

- Pre-SR9 rules for Payments that were exported to BACS pre SR9 date (config)
- Post-SR9 rules thereafter

New columns added:

- BACSDate  : msit_S_AGMPAY.EXPORTED_DATE
- ValidTASHH  : Validation result of TASHH ID held on msit_S_AGMFIL
- SR9Class  : Payment Exported Pre-SR9 or belongs to Post_SR9 class
- FirmType  : Derivation Group 1, 2 or 3

SR9 date held on msit_MIWarehouseCodesandDescriptions table on entry with
ColumnName = 'WH_CONFIG_SR9DATE'

-------------- SR9 CHANGES ----------------------------------------------------

MPC 01/06/2008 
1) Amended command to drop cluster index on PARALLEL_mstt_PaymentsPending
2) Added processing to deduplicate where 1 S_AGMFIL linked to 2 or more S_AGMPAY
3) Added Indexes for deduplicating #owner table to improve performance

-------------- Margin Change ---------------------------------------------------

MPC 25/01/2010
1) Add two columns to mstt_PaymentsPending table (populated by separate procedure):
  DerivedAgentSplit and DerivedMarginAmount.
2) Use parameters to call Process Log displaying row counts where relevant.

-------------- PERFORMANCE IMPROVEMENTS ----------------------------------------

Mike Cawood   25/01/2010    Performance Improvements

1) Performance Improvements. New Run Control parameter @Mode added with two settings:

  'FULL': This triggers the full refresh of the PARALLEL_mstt_PaymentsPending table using the
      primary keys held on the owt_TransformationMovements table. All existing rows 
      are deleted. The load table indexes are dropped and recreated after the insert.

  'MOVE': In this mode only those rows that are linked to daily movements of the Driver
      sa_swift_S_AGMFIL table are processed. The primary keys of these movements 
      are held on the owt_TransformationMovements table with DriverTableName of
      'sa_swift_S_AGMFIL'. All PARALLEL_mstt_PaymentsPending rows with whose ID matches to a primary 
      key held on the movements table are deleted and then inserted from the new data 
      generated by the procedure. Indexes are not dropped/created in this mode.
2) Replace msit_S_AGMFIL by sa_swift_S_AGMFIL.
3) Replace msit_AgentTypeHistory by sa_swift_AgentTypeHistory.
4) Replace msit_AgentHierarchyHistory by sa_swift_AgentHierarchyHistory.
5) Replace msit_transagentsplithierarchyhistory by sa_swift_transagentsplithierarchyhistory.

Mike Cawood   19 February 2010

Fix for Duplicate rows - caused by invalid entries on sa_swift_AgentTypeHistory.
A small subset of agents have rows where the end date has not been set meaning
that two AgentTypeHistory rows selected for a given effective date.

30/03/2010  A Groves  Use flag owt_TransformationMovements.PendingPayments to minimise the
            number of rows to process.

*******************************************************************************/

-- PROCEDURE BODY GOES HERE

--MPC:25/01/2010 New ProcessLog Start
declare   @PhaseStart     varchar(50),
      @PhaseEnd     varchar(50),
      @ProcName     varchar(100),
      @ProgressModule   varchar(50),
      @RowCount     int,
      @ProcessMessage   varchar(100)

set @ProcName   = object_name(@@procid) + ' - ' + @Mode
set @PhaseStart   = 'START'
set @PhaseEnd   = 'END'
set @ProgressModule = 'PP'

exec msp_ProcessLog @PhaseStart, @ProcName, null, @Module, @Client

--MPC:25/01/2010 New ProcessLog End

--MPC:25/01/2010 New Movements Processing - START
/******************************************************************************************************************
    DERIVE MOVEMENTS
******************************************************************************************************************/
CREATE TABLE #AGMFILChanges (ID int)
CREATE INDEX #X ON #AGMFILCHANGES (ID)

CREATE TABLE #TASHHChanges (ID int)
CREATE INDEX #X ON #TASHHCHANGES (ID)

IF @Mode = 'FULL' --FULL Reload of Table
BEGIN

  Insert INTO #AGMFILCHANGES
  Select Distinct ID 
  from sa_swift_S_AGMFIL 

  select @RowCount = @@rowcount
  set @ProcessMessage = @Mode + ' - Identify S_AGMFIL Movements : Count = ' + convert(varchar(10), @RowCount)   
  exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client

  Insert INTO #TASHHCHANGES
  Select Distinct ID 
  from sa_swift_TransAgentSplitHierarchyHistory 

  select @RowCount = @@rowcount
  set @ProcessMessage =  @Mode + ' - Identify TASHH Movements : Count = ' + convert(varchar(10), @RowCount)   
  exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client

END --@Mode = 'FULL'

IF @Mode = 'MOVE' --Process Movements only
BEGIN

  Insert  INTO #AGMFILCHANGES
  Select  DISTINCT PKID as ID
  FROM  owt_TransformationMovements
  Where DriverTableName = 'sa_swift_S_AGMFIL'
  and   PendingPayments = 'Y'             -- AG 30/03/2010

  select @RowCount = @@rowcount
  set @ProcessMessage = @Mode + ' - Identify S_AGMFIL Movements : Count = ' + convert(varchar(10), @RowCount)   
  exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client

  Insert  INTO #TASHHCHANGES
  Select  DISTINCT PKID as ID
  FROM  owt_TransformationMovements
  Where DriverTableName = 'sa_swift_TransAgentSplitHierarchyHistory'
  and   PendingPayments = 'Y'             -- AG 30/03/2010

  select @RowCount = @@rowcount
  set @ProcessMessage = @Mode + ' - Identify TASHH Movements : Count = ' + convert(varchar(10), @RowCount)    
  exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client

END   --@Mode = 'MOVE'
--MPC:25/01/2010 New Movements Processing - END

--Moved to End of Proc          --MPC: SR9 
--Truncate table PARALLEL_mstt_PaymentsPending      --MPC: SR9

declare 
  @DefaultCommissionTypeCode      int,
  @DefaultCommissionTypeDesc      nvarchar(255),
  @DefaultStandingOrderCode     int,
  @DefaultStandingOrderDesc     nvarchar(255),
  @DefaultJournalEntryCode      int,
  @DefaultJournalEntryDesc      nvarchar(255)

set @DefaultCommissionTypeCode  = (select convert(int,DefaultValue) from mstt_DefaultCodeValues where CodeColumn = 'CommissionTypeCode')
set @DefaultCommissionTypeDesc  = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'CommissionTypeDesc')   
set @DefaultStandingOrderCode = (select convert(int,DefaultValue) from mstt_DefaultCodeValues where CodeColumn = 'StandingOrderCode')
set @DefaultStandingOrderDesc = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'StandingOrderDesc')    
set @DefaultJournalEntryCode  = (select convert(int,DefaultValue) from mstt_DefaultCodeValues where CodeColumn = 'JournalEntryCode')
set @DefaultJournalEntryDesc  = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'JournalEntryDesc')   

declare @SR9Date datetime 
set @SR9date = (select CODE from msit_MIWarehouseCodesandDescriptions where ColumnName = 'WH_CONFIG_SR9DATE')
--select @Sr9date

/*
--MPC: SR9 - moved to main Select below
Select pt.ID,
 pt.PolicyID,
 pt.TransactionDate,
 p.PolicyRef,
 p.CONT_NUM,
 p.CLIENT_NUM,
 p.SuspendCommInd,
 pt.ProposalDate,     --MPC: SR9
 pt.CommProductCode     --MPC: SR9  
into #PolicyTransactions
 from mstt_policytransactions pt
 inner join mstt_Policies p
  on pt.PolicyID = p.POL_NUM
*/

select pt.id as TranID,CAST(CONVERT(NVARCHAR, pt.ProposalDate, 112) AS DATETIME) as ProposalDate,tashh.*
into #ActiveTASHHList
from sa_swift_policytransactions pt                   --MPC:25/01/2010
inner join sa_swift_transagentsplithierarchyhistory tashh       --MPC:25/01/2010
  on pt.id = tashh.transactionid and tashh.active = 1 
inner join #TASHHCHANGES X ON X.ID = tashh.Id             --MPC:25/01/2010
where pt.id in (select distinct transactionid from sa_swift_S_AGMFIL) --MPC:25/01/2010
order by pt.id,tashh.commissiontype

create clustered index idx_ID on #ActiveTASHHList(TranID)

select ID,
case 
when (franchiseagentcode is null and accessagentcode is null and directlyauthorisedagentcode is null) then 'E01'
when (franchiseagentcode is not null and accessagentcode is not null) then 'E02'
when (franchiseagentcode is not null and directlyauthorisedagentcode is not null) then 'E03'
when (accessagentcode is not null and directlyauthorisedagentcode is not null) then 'E04'
when (franchiseagentcode is not null and franchiseagentcode not in (select distinct agentcode from msit_agenttypehistory where agenttype = 2) ) then 'E05'
when (accessagentcode is not null and accessagentcode not in (select distinct agentcode from msit_agenttypehistory where agenttype = 46) ) then 'E06'
when (directlyauthorisedagentcode is not null and directlyauthorisedagentcode not in (select distinct agentcode from msit_agenttypehistory where agenttype = 49) ) then 'E07'
when (manager2code is null or manager2code not in (select distinct agentcode from msit_agenttypehistory where agenttype = 53) ) then 'E08'
when (organisationagentcode is null or organisationagentcode not in (select distinct agentcode from msit_agenttypehistory where agenttype = 19) ) then 'E09'
when (companyagentcode is null or companyagentcode not in (select distinct agentcode from msit_agenttypehistory where agenttype = 42) ) then 'E10'
end as ErrCode
into #InvalidTASHH
from sa_swift_transagentsplithierarchyhistory tash    --MPC:25/01/2010
where  
( 
   (franchiseagentcode is null and accessagentcode is null and directlyauthorisedagentcode is null)
or (franchiseagentcode is not null and accessagentcode is not null) 
or (franchiseagentcode is not null and directlyauthorisedagentcode is not null) 
or (accessagentcode is not null and directlyauthorisedagentcode is not null)
or (franchiseagentcode is not null and franchiseagentcode not in (select distinct agentcode from msit_agenttypehistory where agenttype = 2) )
or (accessagentcode is not null and accessagentcode not in (select distinct agentcode from msit_agenttypehistory where agenttype = 46) )
or (directlyauthorisedagentcode is not null and directlyauthorisedagentcode not in (select distinct agentcode from msit_agenttypehistory where agenttype = 49) )
or (manager2code is null or manager2code not in (select distinct agentcode from msit_agenttypehistory where agenttype = 53) )
or (organisationagentcode is null or organisationagentcode not in (select distinct agentcode from msit_agenttypehistory where agenttype = 19) )
or (companyagentcode is null or companyagentcode not in (select distinct agentcode from msit_agenttypehistory where agenttype = 42) )
)
order by ID

create clustered index idx_ID on #InvalidTASHH(ID)

select DISTINCT t1.ID
,max(case when ahh_org.id is null then 1 when ahh_org.id is not null and ahh_org.detailagentcode <> t1.organisationagentcode then 2 else 0 end) as OrgStatus
,max(case when ahh_comp.id is null then 1 when ahh_comp.id is not null and ahh_comp.detailagentcode <> t1.companyagentcode then 2 else 0 end) as CompStatus
,max(case when ahh_man2.id is null then 1 when ahh_man2.id is not null and ahh_man2.detailagentcode <> t1.manager2code then 2 else 0 end) as Man2Status
,max(case when ahh_bus.id is null then 1 when ahh_bus.id is not null and ahh_bus.detailagentcode <> coalesce(t1.franchiseagentcode,t1.accessagentcode,t1.directlyauthorisedagentcode) then 2 else 0 end) as BusStatus
into #TASHHCheckHier
from #ActiveTashhList t1
left outer join sa_swift_AgenthierarchyHistory AHH_ORG    --MPC:25/01/2010
on t1.agentcode = AHH_ORG.agentcode and AHH_ORG.participanttype = 0 and AHH_ORG.defaultvalue = 1
and t1.proposaldate between AHH_ORG.startdate and isnull(AHH_ORG.enddate,'31 dec 2999')
left outer join sa_swift_AgenthierarchyHistory AHH_COMP   --MPC:25/01/2010
on t1.agentcode = AHH_COMP.agentcode and AHH_COMP.participanttype = 1 and AHH_COMP.defaultvalue = 1
and t1.proposaldate between AHH_COMP.startdate and isnull(AHH_COMP.enddate,'31 dec 2999')
left outer join sa_swift_AgenthierarchyHistory AHH_MAN2   --MPC:25/01/2010
on t1.agentcode = AHH_MAN2.agentcode and AHH_MAN2.participanttype = 4 and AHH_MAN2.defaultvalue = 1
and t1.proposaldate between AHH_MAN2.startdate and isnull(AHH_MAN2.enddate,'31 dec 2999')
left outer join sa_swift_AgenthierarchyHistory AHH_BUS    --MPC:25/01/2010
on t1.agentcode = AHH_BUS.agentcode and AHH_BUS.participanttype in (6,7,8,9) and AHH_BUS.defaultvalue = 1
and t1.proposaldate between AHH_BUS.startdate and isnull(AHH_BUS.enddate,'31 dec 2999')
where t1.ID not in (select ID from #InvalidTASHH)
group by t1.id
order by 1

create clustered index idx_ID on #TASHHCheckHier(ID)

select t1.ID,t1.ErrCode,null as OrgErr,null as CompErr,null as Man2Err,null as BusErr
into #InvalidTASHH_ALL
from #InvalidTASHH t1
UNION ALL
select t2.ID,null as ErrCode,
case t2.OrgStatus when 1 then 'E11' when 2 then 'E12' end as OrgErr,
case t2.CompStatus when 1 then 'E13' when 2 then 'E14' end as CompErr,
case t2.Man2Status when 1 then 'E15' when 2 then 'E16' end as Man2Err,
case t2.BusStatus when 1 then 'E17' when 2 then 'E18' end as BusErr
from #TASHHCheckHier t2
where t2.OrgStatus > 0 or t2.CompStatus > 0 or t2.Man2Status > 0 or t2.BusStatus > 0
order by 1

create clustered index idx_ID on #InvalidTASHH_ALL(ID)

exec msp_ProcessLog @PhaseEnd, 'TASHH Processing', null, @ProgressModule, @Client --MPC:25/01/2010

--MPC: SR9 - moved to Top
select distinct Code as AgentType
into #SellerAgentType
from msit_MIWarehouseCodesAndDescriptions
where ColumnName = 'LG-AgtType'
and Description = 'Seller'
order by Code

--Extract valid AgentTypeHistory entries  START   MPC:19/02/2010
select agentcode,agenttype,startdate,enddate
into #AgentTypeHistory
from sa_swift_AgentTypeHistory
where startdate <= isnull(enddate,'31 dec 2999')  --excludes rows where StartDate > EndDate
order by 1,3

update #agenttypehistory
set enddate = '31 dec 2999'

--Reset EndDate as lowest StartDate - 1 day from rows with later StartDate for Agent
update #agenttypehistory
set enddate = A.enddate
from #agenttypehistory ath3 
inner join 
(select ath1.agentcode,ath1.agenttype,ath1.startdate,enddate = min(dateadd(dd,-1,ath2.startdate))
from #agenttypehistory ath1
inner join #agenttypehistory ath2 
on ath1.agentcode = ath2.agentcode and ath2.startdate > ath1.startdate
group by ath1.agentcode,ath1.agenttype,ath1.startdate) A
on a.agentcode = ath3.agentcode and a.startdate = ath3.startdate
--Extract valid AgentTypeHistory entries  END   MPC:19/02/2010

-- Create Temp Table to hold Firm and associated details for each Payment (exclude Org, Company, Pot Accounts)

create table #Owner
(AGMFILID int null,
TranId int null,
TASHHID int null,
Agent varchar(7) null,
AgentType int null,
BACSType int null,
CreateType int null,
AgentFirm varchar(7) null,
TASHFirm varchar(7) null,
BACSHierID int null,
BACSFirm varchar(7) null,
CreateHierID int null,
Createfirm varchar(7) null,
AGMPAYID int null,
BACSDate datetime null,
CreateDate datetime null,
SR9Class varchar(5) null,
ValidTASHH varchar(5) null,
Active int null,
BACSOwner varchar(7) null,
Firm varchar(7) null,
FirmType varchar(1) null,
DUP varchar(1) null)

insert into #Owner
select DISTINCT
a.ID as AGMFILID,
isnull(a.TransactionID,0) as TranID,
a.TransAgentSplitHierarchyHistoryID as TASHHID,
a.Agent_Code as Agent,
ag.AgentType,
atb.AgentType as BACSType,
atc.AgentType as CreateType,
ag.Firm as AgentFirm,
coalesce(tash.FranchiseAgentCode,tash.DirectlyAuthorisedAgentCode,tash.AccessAgentCode,tash.StrategicAllianceAgentCode) as TASHFirm,
ahb.ID as BACSHierID,
ahb.DetailAgentcode as BACSFirm,
ahC.ID as CreateHierID,
ahc.DetailAgentcode as CreateFirm,
pay.ID as AGMPAYID,
pay.export_date as BACSDate,
a.createdatetime as CreateDate,
case when pay.id is not null and CAST(CONVERT(NVARCHAR, pay.export_date, 112) AS DATETIME) < @SR9Date then 'PRE' else 'POST' end as SR9Class,
case when t1.id is not null and t1.ErrCode is not null then t1.ErrCode
when t1.id is not null and t1.ErrCode is null then coalesce(t1.BusErr,t1.Man2Err,t1.CompErr,t1.OrgErr)  
when a.TransAgentSplitHierarchyHistoryID is not null and t1.id is null then 'Valid'
when a.TransAgentSplitHierarchyHistoryID is null and isnull(a.TransactionID,0) > 0 then 'E99'
end as ValidTASHH,
isnull(tash.Active,0) as Active,
coalesce(PreSR9.FIRM,BACS.PaidToAgentCode) as BACSOwner,
NULL as Firm,
'X' as FirmType,
NULL as DUP

from
 sa_swift_S_AGMFIL a                    --MPC:25/01/2010
 inner join #AGMFILCHANGES X ON X.ID = A.ID         --MPC:25/01/2010
 left outer join sa_swift_s_AGMPAY pay            --MPC: SR9    --MPC:25/01/2010
  on pay.agmid = a.ID                   --MPC: SR9
 left outer join #InvalidTASHH_ALL t1             --MPC: SR9
  on t1.id = a.TransAgentSplitHierarchyHistoryID      --MPC: SR9
 left outer join msit_TransAgentSplitHierarchyHistory tash  --MPC: SR9
  on a.TransAgentSplitHierarchyHistoryID = tash.[ID]    --MPC: SR9
 inner join mstt_Agents ag                  --MPC: SR9
  on ag.code = a.agent_code               --MPC: SR9
 left outer join sa_swift_AgenthierarchyHistory ahb     --MPC:25/01/2010
  on ahb.agentcode = a.agent_code and ahb.participanttype in (6,7,8,9) and ahb.defaultvalue = 1 
  and CAST(CONVERT(NVARCHAR,pay.export_date, 112) AS DATETIME) between ahb.startdate and isnull(ahb.enddate,'31 Dec 2999')
 left outer join sa_swift_AgenthierarchyHistory ahc     --MPC:25/01/2010
  on ahc.agentcode = a.agent_code and ahc.participanttype in (6,7,8,9) and ahc.defaultvalue = 1 
  and CAST(CONVERT(NVARCHAR,a.Createdatetime, 112) AS DATETIME) between ahc.startdate and isnull(ahc.enddate,'31 Dec 2999')
 --left outer join sa_swift_AgentTypeHistory atb      --MPC:25/01/2010
 left outer join #AgentTypeHistory atb            --MPC:19/02/2010
  on atb.agentcode = a.agent_code  
  and CAST(CONVERT(NVARCHAR,pay.export_date, 112) AS DATETIME) between atb.startdate and isnull(atb.enddate,'31 Dec 2999')
 --left outer join sa_swift_AgentTypeHistory atc      --MPC:25/01/2010
 left outer join #AgentTypeHistory atc            --MPC:19/02/2010
  on atc.agentcode = a.agent_code 
  and CAST(CONVERT(NVARCHAR,a.Createdatetime, 112) AS DATETIME) between atc.startdate and isnull(atc.enddate,'31 Dec 2999')
 left outer join owt_PreSR9BACSPaymentOwner PreSR9
  on pay.ID = PreSR9.AGMPAYID
 left outer join sa_swift_TempBACSExportHistory BACS    --MPC:25/01/2010
  on pay.ID = BACS.S_AGMPAY_ID 
where ag.agenttype not in (19,42,48) 
order by a.ID

drop table #agenttypehistory    --MPC:19/02/2010

-- Apply Ownership Rules

update #owner 
Set 
Firm = case   when BACSOwner is not NULL then BACSOwner
    when SR9Class = 'PRE' and ValidTashh = 'Valid' then TashFirm
    when SR9Class = 'PRE' and ValidTashh in ('E08','E09','E10') then TashFirm
    when SR9Class = 'PRE' and isnull(bacstype,agenttype) not in (select distinct agenttype from #SellerAgentType) then Agent
    when SR9Class = 'PRE' and isnull(bacstype,agenttype) in (select distinct agenttype from #SellerAgentType) and BACSFirm is not null then BACSFirm
    when SR9Class = 'PRE' and isnull(bacstype,agenttype) in (select distinct agenttype from #SellerAgentType) then AgentFirm
    when SR9Class = 'POST' and ValidTashh = 'Valid' then TashFirm
    when SR9Class = 'POST' and Active = 0 and ValidTashh in ('E11','E12','E13','E14','E15','E16','E17','E18') then TashFirm
    when SR9Class = 'POST' and TranID = 0 and isnull(createtype,agenttype) not in (select distinct agenttype from #SellerAgentType) then Agent
    when SR9Class = 'POST' and TranID = 0 and isnull(createtype,agenttype) in (select distinct agenttype from #SellerAgentType) and CreateFirm is not null then CreateFirm
    else NULL
    end,
FirmType = case when SR9Class = 'PRE' and ValidTashh = 'Valid' then 'A'
    when SR9Class = 'PRE' and ValidTashh in ('E08','E09','E10') then 'A'
    when SR9Class = 'PRE' and isnull(bacstype,agenttype) not in (select distinct agenttype from #SellerAgentType) then 'B'
    when SR9Class = 'PRE' and isnull(bacstype,agenttype) in (select distinct agenttype from #SellerAgentType) and BACSFirm is not null then 'C'
    when SR9Class = 'PRE' and isnull(bacstype,agenttype) in (select distinct agenttype from #SellerAgentType) then 'D'
    when SR9Class = 'POST' and ValidTashh = 'Valid' then 'A'
    when SR9Class = 'POST' and Active = 0 and ValidTashh in ('E11','E12','E13','E14','E15','E16','E17','E18') then 'E'
    when SR9Class = 'POST' and TranID = 0 and isnull(createtype,agenttype) not in (select distinct agenttype from #SellerAgentType) then 'B'
    when SR9Class = 'POST' and TranID = 0 and isnull(createtype,agenttype) in (select distinct agenttype from #SellerAgentType) and CreateFirm is not null then 'C'
    else 'X'
    end

create clustered index idx_ID on #Owner(AGMFILID)
create index idx_Dup1 on #Owner(AGMFILID,BacsHierID,CreateHierID) --MPC: 01/06/08 (3)
create index idx_Dup2 on #Owner(AGMFILID,AGMPAYID)          --MPC: 01/06/08 (3)

-- Dedup #owner to cope with Agent Hierarchy Dups
select AGMFILID,max(BacsHierID) as MaxBACSID,max(CreateHierID) as MaxCreateId
into #owner_max
from #owner 
where BacsHierID is not null or CreateHierID is not null
group by AGMFILID
order by AGMFILID

update #owner
set DUP = 1
from #owner t1
inner join #owner_max t2 on t1.AGMFILID = t2.AGMFILID
where (t1.BacsHierID <> t2.MaxBACSID and t1.BacsHierID is not null)
or (t1.CreateHierID <> t2.MaxCreateId and t1.CreateHierID is not null)

delete from #owner where DUP = 1

drop table #owner_max

--MPC: 01/06/08 (2) START
-- Dedup #Owner to remove duplicates created by one S_AGMFIL row being linked to 2 or more S_AGMPAY rows

select AGMFILID,count(*) as Count,min(AGMPAYID) as FirstAGMPAY
into #owner_dups
from #owner
where AGMPAYID is not null
group by AGMFILID having count(*) > 1

update #owner 
set DUP = (case  when t1.AGMPAYID <> t2.FirstAGMPAY then 1
    else NULL
    end)
from #owner t1
inner join #owner_dups t2 on t1.AGMFILID = t2.AGMFILID
where t1.AGMPAYID is not null

delete from #owner where DUP = 1

drop table #owner_dups
--MPC: 01/06/08 (2) END

-- Apply Firm Overrides from BI Config

select Code as ID,Description as NewFirm
into #OverrideFirm
from msit_MIWarehouseCodesandDescriptions
where ColumnName = 'WH_CONFIG_PayPend_FIRM'
Order by 1

Update #owner
set Firm = t2.NewFirm,FirmType = 'O'
from #owner t1 inner join #OverrideFirm t2 on t1.AGMFILID = t2.ID

drop table #OverrideFirm

exec msp_ProcessLog @PhaseEnd, 'OWNER Processing', null, @ProgressModule, @Client   --MPC:25/01/2010

-- Now create Temp Table to hold Payment Pending rows

Select ID,AGENT_CODE,COMP_CODE,AMOUNT,CommissionType,CommissionTypeDesc,YTD,STATEMENT,PACC_ID,AMOUNT_PAID,DUE_DATE,
STATUS,MEDONE,Notes,ContraID,StandingOrderCode,StandingOrderCodeDesc,JournalEntryCode,JournalEntryCodeDesc,PaymentDueDate,
TransactionID,TransactionDate,PaymentBasis,SubjectToVAT,Authorised,CreatedBy,CreatedDate,AuthorisedBy,AuthorisedDate,
StandingOrderID,BaseAmount,UpliftAmount,CreateDateTime,TransAgentSplitHierarchyHistoryID,StrategicAllianceAgentCode,
AccessAgentCode,FranchiseAgentCode,CompanyAgentCode,OrganisationAgentCode,DirectlyAuthorisedAgentCode,Manager1Code,
Manager2Code,Manager3Code,Manager4Code,AGENT_PERC,FranchiseUpliftPercent,CommissionMonth,PolicyID,CaseID,ProviderRef,
FirstClientID,SuspendCommInd,TranProduct,Firm,BACSDate,ValidTASHH,SR9Class,FirmType
,DerivedAgentSplit,DerivedMarginAmount      --MPC:25/01/2010
into #PARALLEL_mstt_PaymentsPending 
from PARALLEL_mstt_PaymentsPending
where 1=0 

insert into #PARALLEL_mstt_PaymentsPending    --MPC: SR9
select
 a.[ID],    
 a.AGENT_CODE,
 a.COMP_CODE,
 a.AMOUNT,
 isnull(a.TYPE,@DefaultCommissionTypeCode) as CommissionType,           --MPC: SR9
 case           --CommissionTypeDesc                --MPC: SR9
  when a.Type is not null then (select dl.Description from msdt_DropLists dl  --MPC: SR9
              where dl.CodeType = 'CommissionType' and a.Type = dl.Code)  --MPC: SR9
  else @DefaultCommissionTypeDesc                       --MPC: SR9
 end as CommissionTypeDesc,                           --MPC: SR9
 a.YTD,
 a.STATEMENT,
 a.PACC_ID,
 a.AMOUNT_PAID,
 a.DUE_DATE,
 a.STATUS,
 a.MEDONE,
 a.Notes,
 a.ContraID,
 isnull(a.StandingOrderCode,@DefaultStandingOrderCode) as StandingOrderCode,--MPC: SR9
 case           --StandingOrderCodeDesc             --MPC: SR9
  when a.StandingOrderCode is not null then (select dl.Description from  msit_CodeStandingOrders dl --MPC: SR9
                    where a.StandingOrderCode = dl.Code)      --MPC: SR9
  else @DefaultStandingOrderDesc                      --MPC: SR9
 end as StandingOrderCodeDesc,                        --MPC: SR9
 isnull(a.JournalEntryCode ,@DefaultJournalEntryCode) as JournalEntryCode,  --MPC: SR9
 case           --JournalEntryCodeDesc              --MPC: SR9
  when a.JournalEntryCode is not null then (select dl.Description from msit_CodeJournalEntries dl --MPC: SR9
                    where a.JournalEntryCode  = dl.Code)      --MPC: SR9
  else @DefaultJournalEntryDesc                       --MPC: SR9
 end as JournalEntryCodeDesc,                       --MPC: SR9
 a.PaymentDueDate,
 a.TransactionID,
 pt.TransactionDate,                            --MPC: SR9
 a.PaymentBasis,
 a.SubjectToVAT,
 a.Authorised,
 a.CreatedBy,
 a.CreatedDate,
 a.AuthorisedBy,
 a.AuthorisedDate,
 a.StandingOrderID,
 a.BaseAmount,
 a.UpliftAmount,
 a.CreateDateTime,
 a.TransAgentSplitHierarchyHistoryID,
 b.StrategicAllianceAgentCode,    --MPC: SR9
 b.AccessAgentCode,         --MPC: SR9
 b.FranchiseAgentCode,        --MPC: SR9
 b.CompanyAgentCode,        --MPC: SR9
 b.OrganisationAgentCode,     --MPC: SR9
 b.DirectlyAuthorisedAgentCode,   --MPC: SR9
 b.Manager1Code,          --MPC: SR9
 b.Manager2Code,          --MPC: SR9
 '       ' as Manager3Code,     --MPC: SR9
 '       ' as Manager4Code,     --MPC: SR9
 a.AGENT_PERC,
 a.FranchiseUpliftPercent,
 csp.Month as CommissionMonth,    --MPC: SR9
 pt.PolicyID,           --MPC: SR9
 po.PolicyRef,            --MPC: SR9
 po.CONT_NUM,           --MPC: SR9
 po.CLIENT_NUM,           --MPC: SR9
 po.SuspendCommInd,         --MPC: SR9
 pt.CommProductCode as TranProduct, --MPC: SR9
 t2.FIRM,             --MPC: SR9
 t2.BACSDate,           --MPC: SR9
 t2.ValidTASHH,           --MPC: SR9 
 t2.SR9Class,           --MPC: SR9
 t2.FIRMTYPE            --MPC: SR9
 ,NULL as DerivedAgentSplit     --MPC:25/01/2010
 ,NULL as DerivedMarginAmount   --MPC:25/01/2010

from
 msit_S_AGMFIL a
 inner join #AGMFILCHANGES X ON X.ID = A.ID       --MPC:25/01/2010
 left outer join mstt_PolicyTransactions pt       --MPC: SR9
  on a.transactionid = pt.id              --MPC: SR9
 left outer join mstt_Policies po             --MPC: SR9
  on pt.policyid = po.pol_num             --MPC: SR9
-- left outer join msit_s_AGMPAY pa           --MPC: SR9
--  on pa.agmid = a.ID                  --MPC: SR9
 left outer join msit_CommissionStatementPeriods csp  --MPC: SR9
  on CAST(CONVERT(NVARCHAR, a.CreateDateTime, 112) AS DATETIME) between csp.PeriodStartDate and csp.PeriodEndDate   --MPC: SR9
 left outer join #InvalidTASHH t1             --MPC: SR9
  on t1.id = a.TransAgentSplitHierarchyHistoryID    --MPC: SR9
 left outer join msit_TransAgentSplitHierarchyHistory b --MPC: SR9
  on a.TransAgentSplitHierarchyHistoryID = b.[ID]   --MPC: SR9
-- inner join mstt_Agents ag              --MPC: SR9
--  on ag.code = a.agent_code             --MPC: SR9
 left outer join #Owner t2                --MPC: SR9
  on t2.AGMFILid = a.ID               --MPC: SR9
-- where a.transactionid *= p.id            --MPC: SR9

select @RowCount = @@rowcount   --MPC:25/01/2010
set @ProcessMessage = @Mode + ' - Select S_AGMFIL Records : Count = ' + convert(varchar(10), @RowCount)   --MPC:25/01/2010
exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client    --MPC:25/01/2010

