/************************************************************************************************
  PERFORM DATABASE UPDATES
************************************************************************************************/

--Full Refresh - Truncate Table, Drop Indexes, Insert then Create Undexes
IF @Mode = 'FULL' --MPC:25/01/2010
BEGIN       --MPC:25/01/2010

  --Clear the target table first
  Truncate table PARALLEL_mstt_PaymentsPending

  DROP  INDEX PARALLEL_mstt_PaymentsPending.IX_PaymentPendingCommType
  DROP  INDEX PARALLEL_mstt_PaymentsPending.IX_PaymentPendingAgent
  DROP  INDEX PARALLEL_mstt_PaymentsPending.IX_PaymentPendingSO
  DROP  INDEX PARALLEL_mstt_PaymentsPending.IX_PaymentsPending_PACC
  DROP  INDEX PARALLEL_mstt_PaymentsPending.IX_PaymentsPending_Trial
  DROP  INDEX PARALLEL_mstt_PaymentsPending.IX_PaymentsPending_FranAgntCd_AccAgentCd_DirAuthAgntCd_TranID_CreateDT_CommTyp_PymtDuDt_AMT
  DROP  INDEX PARALLEL_mstt_PaymentsPending.PK_PARALLEL_mstt_PaymentsPending      --MPC: 01/06/08 (1)
  --ALTER TABLE PARALLEL_mstt_PaymentsPending DROP CONSTRAINT PK_PARALLEL_mstt_PaymentsPending  --MPC: 01/06/08 (1)

  --Main Insert
  insert into PARALLEL_mstt_PaymentsPending
  select * from #PARALLEL_mstt_PaymentsPending

  select @RowCount = @@rowcount       --MPC:25/01/2010
  set @ProcessMessage = @Mode + ' - mstt_PaymentsPending INSERTED : Count = ' + convert(varchar(10), @RowCount) --MPC:25/01/2010
  exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client      --MPC:25/01/2010

  CREATE  CLUSTERED  INDEX [PK_PARALLEL_mstt_PaymentsPending] ON [dbo].[PARALLEL_mstt_PaymentsPending](ID) ON [PRIMARY]
  CREATE  INDEX [IX_PaymentPendingCommType] ON [dbo].[PARALLEL_mstt_PaymentsPending](CommissionType,Due_Date) ON [PRIMARY]
  CREATE  INDEX [IX_PaymentPendingAgent] ON [dbo].[PARALLEL_mstt_PaymentsPending](Agent_Code,CommissionType,Due_Date,StandingOrderCode) ON [PRIMARY]
  CREATE  INDEX [IX_PaymentPendingSO] ON [dbo].[PARALLEL_mstt_PaymentsPending](StandingOrderCode) ON [PRIMARY]
  CREATE  INDEX [IX_PaymentsPending_PACC] ON [dbo].[PARALLEL_mstt_PaymentsPending](PACC_ID) ON [PRIMARY]
  CREATE  INDEX [IX_PaymentsPending_Trial] ON [dbo].[PARALLEL_mstt_PaymentsPending](ID,CommissionType,PaymentDueDate,Agent_Code,Amount) ON [PRIMARY]
  CREATE  INDEX [IX_PaymentsPending_FranAgntCd_AccAgentCd_DirAuthAgntCd_TranID_CreateDT_CommTyp_PymtDuDt_AMT] ON [dbo].[PARALLEL_mstt_PaymentsPending](FranchiseAgentCode,AccessAgentCode,DirectlyAuthorisedAgentCode,TransactionID,CreateDateTime,CommissionType,PaymentDueDate,Amount) ON [PRIMARY]

  exec msp_ProcessLog @PhaseEnd, 'Indexes CREATED', null, @ProgressModule, @Client

  --MPC:25/01/2010  DatabaseUPDATE Changes - START

END --  @Mode = 'FULL'

--Delete existing rows in Movements List then Insert new Movements
IF @Mode = 'MOVE'   
BEGIN

  --DELETE Movements only
  DELETE FROM PARALLEL_mstt_PaymentsPending
  WHERE ID IN (Select ID From #AGMFILChanges)   

  select @RowCount = @@rowcount
  set @ProcessMessage = @Mode + ' - Delete Data : Count = ' + convert(varchar(10), @RowCount)   --MPC:25/01/2010
  exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client      --MPC:25/01/2010

  --Main Insert
  insert into PARALLEL_mstt_PaymentsPending
  select * from #PARALLEL_mstt_PaymentsPending

  select @RowCount = @@rowcount
  set @ProcessMessage = @Mode + ' - InsertData : Count = ' + convert(varchar(10), @RowCount) --MPC:25/01/2010
  exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client    --MPC:25/01/2010

  UPDATE STATISTICS PARALLEL_mstt_PaymentsPending

  exec msp_ProcessLog @PhaseEnd, 'UPDATE STATISTICS', null, @ProgressModule, @Client

END --@Mode = 'MOVE'

--MPC:25/01/2010  DatabaseUPDATE Changes - END

/******************************************************************************************************************
    END of PROCESSING
******************************************************************************************************************/
drop table #PARALLEL_mstt_PaymentsPending

--END
exec msp_ProcessLog @PhaseEnd, @ProcName, null, @Module, @Client    --MPC:25/01/2010







