create procedure [dbo].[pb_ABS_upd_dbo_ABS_CaseDocuments]
		@c1 int = NULL,
		@c2 int = NULL,
		@c3 nvarchar(200) = NULL,
		@c4 nvarchar(350) = NULL,
		@c5 bigint = NULL,
		@c6 bigint = NULL,
		@c7 int = NULL,
		@c8 int = NULL,
		@c9 bit = NULL,
		@c10 datetime = NULL,
		@pkc1 int = NULL,
		@bitmap binary(2)
as
begin  
	declare @primarykey_text nvarchar(100) = ''
update [dbo].[sa_abs_ABS_CaseDocuments] set
		[CaseID] = case substring(@bitmap,1,1) & 2 when 2 then @c2 else [CaseID] end,
		[FileName] = case substring(@bitmap,1,1) & 4 when 4 then @c3 else [FileName] end,
		[WorkingFileLocation] = case substring(@bitmap,1,1) & 8 when 8 then @c4 else [WorkingFileLocation] end,
		[ExpectedFileLength] = case substring(@bitmap,1,1) & 16 when 16 then @c5 else [ExpectedFileLength] end,
		[ActualFileBytesWritten] = case substring(@bitmap,1,1) & 32 when 32 then @c6 else [ActualFileBytesWritten] end,
		[FileChunkSize] = case substring(@bitmap,1,1) & 64 when 64 then @c7 else [FileChunkSize] end,
		[FileChunksWritten] = case substring(@bitmap,1,1) & 128 when 128 then @c8 else [FileChunksWritten] end,
		[IsComplete] = case substring(@bitmap,2,1) & 1 when 1 then @c9 else [IsComplete] end,
		[DateUpdated] = case substring(@bitmap,2,1) & 2 when 2 then @c10 else [DateUpdated] end
	where [ID] = @pkc1
if @@rowcount = 0
    if @@microsoftversion>0x07320000
		Begin
			if exists (Select * from sys.all_parameters where object_id = OBJECT_ID('sp_MSreplraiserror') and [name] = '@param3')
			Begin
				
				set @primarykey_text = @primarykey_text + '[ID] = ' + convert(nvarchar(100),@pkc1,1)
				exec sp_MSreplraiserror @errorid=20598, @param1=N'[dbo].[sa_abs_ABS_CaseDocuments]', @param2=@primarykey_text, @param3=13233 
			End
			Else
				exec sp_MSreplraiserror @errorid=20598
		End
end 
